nodes.failure_modes:
\begin{itemize}
  \item \textbf{Failure of upper control.} There exists an element of $A$ strictly larger than $u$.
  \item \textbf{Failure of bounding from above.} The element $u$ does not sit above all elements of $A$.
\end{itemize}

\begin{itemize}
  \item \textbf{Failure of lower control.} There exists an element of $A$ strictly smaller than $\ell$.
  \item \textbf{Failure of bounding from below.} The element $\ell$ does not sit below all elements of $A$.
\end{itemize}

\begin{itemize}
  \item \textbf{Failure of membership.} The candidate $m$ is not an element of $A$.
  \item \textbf{Failure of leastness.} There exists an element of $A$ strictly smaller than $m$.
\end{itemize}

\begin{itemize}
  \item \textbf{Failure of membership.} The candidate $m$ is not an element of $A$.
  \item \textbf{Failure of greatestness.} There exists an element of $A$ strictly larger than $m$.
\end{itemize}

\begin{itemize}
  \item \textbf{Failure to be an upper bound.} There exists an element of $A$ strictly larger than $s$, so $s$ does not bound $A$ from above at all.
  \item \textbf{Failure to be the least upper bound.} The element $s$ may still be an upper bound, but there exists a smaller upper bound $u < s$, so $s$ is not the least one.
\end{itemize}

\begin{itemize}
  \item \textbf{Failure to be a lower bound.} There exists an element of $A$ strictly smaller than $t$, so $t$ does not bound $A$ from below at all.
  \item \textbf{Failure to be the greatest lower bound.} The element $t$ may still be a lower bound, but there exists a greater lower bound $\ell > t$, so $t$ is not the greatest one.
\end{itemize}

\begin{itemize}
  \item \textbf{Failure of upper-bound control.} There exists an element of $A$ strictly larger than $s$.
  \item \textbf{Failure of the supremum condition.} Any such example contradicts the fact that a supremum is an upper bound of the set.
\end{itemize}

\begin{itemize}
  \item \textbf{Failure of unboundedness.} There exists a real number $x$ that bounds every natural number from above.
  \item \textbf{Failure of Archimedean behavior.} The copy of $\mathbb{N}$ inside $\mathbb{R}$ would stop growing past a fixed real number.
\end{itemize}

\begin{itemize}
  \item \textbf{Failure of growth under repeated addition.} There exists a positive real number $x$ whose natural multiples never exceed some fixed real number $y$.
  \item \textbf{Failure of Archimedean behavior.} Repeatedly adding a positive amount would not eventually pass every prescribed real threshold.
\end{itemize}

\begin{itemize}
  \item \textbf{Failure of existence.} There exists a nonempty subset of $\mathbb{R}$ that is bounded above but has no supremum in $\mathbb{R}$.
  \item \textbf{Failure of the field.} The problem is not in the subset alone. The failure is that $\mathbb{R}$ would be missing the element that should serve as the least upper bound.
\end{itemize}

nodes.failure_mode_decomposition:
\[
\begin{aligned}
&\neg \operatorname{LeastUpperBoundProperty}(\mathbb{R})
\\
&\qquad\Longleftrightarrow\qquad
\exists A \subseteq \mathbb{R}\;
\Bigl[
(A \neq \varnothing \land \operatorname{BoundedAbove}(A))
\\
&\qquad\qquad\land
\forall s \in \mathbb{R}\;
\Bigl(
\underbrace{\exists x \in A\;(s < x)}_{\text{$s$ fails to be an upper bound}}
\;\lor\;
\underbrace{\exists v \in \mathbb{R}\;(\operatorname{UpperBound}(v,A) \land v < s)}_{\text{$s$ fails to be the least upper bound}}
\Bigr)
\Bigr].
\end{aligned}
\]

nodes.failure_modes:
\begin{itemize}
  \item \textbf{Failure of approximation.} There exists a point of $S$ that cannot~\\ be approximated arbitrarily closely by points of $D$.
  \item \textbf{Failure of local presence.} There exists a positive radius around some point of $S$ whose entire neighborhood misses $D$.
\end{itemize}

\begin{itemize}
  \item \textbf{Failure of interval penetration.} There exists a pair of points $a<b$ in $X$ such that no element of $A$ lies strictly between them.
  \item \textbf{Failure of order presence.} There exists a nonempty open interval in $X$ that is missed entirely by $A$.
\end{itemize}

\begin{itemize}
  \item \textbf{Failure of interval penetration.} There exists a pair of real numbers $a<b$ such that no rational number lies strictly between them.
  \item \textbf{Failure of density.} There exists a nonempty open interval in $\mathbb{R}$ that is missed entirely by $\mathbb{Q}$.
\end{itemize}

\begin{itemize}
  \item \textbf{Failure of interval penetration.} There exists a pair of real numbers $a<b$ such that no irrational number lies strictly between them.
  \item \textbf{Failure of density.} There exists a nonempty open interval in $\mathbb{R}$ that is missed entirely by $\mathbb{R}\setminus\mathbb{Q}$.
\end{itemize}

\begin{itemize}
  \item \textbf{Failure of rational presence.} There exists a nonempty open interval in $\mathbb{R}$ containing no rational number.
  \item \textbf{Failure of irrational presence.} There exists a nonempty open interval in $\mathbb{R}$ containing no irrational number.
\end{itemize}

nodes.failure_mode_decomposition:
\[
\exists a,b \in \mathbb{R}\;
\Bigl[
a<b \land
\Bigl(
\underbrace{\forall q \in \mathbb{Q}\; (q \le a \lor b \le q)}_{\text{the interval contains no rational number}}
\;\lor\;
\underbrace{\forall s \in \mathbb{R}\setminus\mathbb{Q}\; (s \le a \lor b \le s)}_{\text{the interval contains no irrational number}}
\Bigr)
\Bigr].
\]

nodes.failure_modes:
\begin{itemize}
  \item \textbf{Failure of common containment.} The intervals remain nested, but no single real number lies in all of them.
  \item \textbf{Failure of completeness behavior.} The nesting construction keeps restricting location, yet the real line would still fail to retain a common point.
\end{itemize}

nodes.failure_mode_decomposition:
\[
\exists (I_n)\;
\Bigl[
\underbrace{\operatorname{NestedIntervalSequence}(I_n)}_{\text{the intervals remain nested}}
\land
\underbrace{\neg \operatorname{NonemptySet}\!\left(\bigcap_{n=1}^{\infty} I_n\right)}_{\text{the total intersection is empty}}
\Bigr].
\]
